function walkTranslate(en){const walker=document.createTreeWalker(document.body,NodeFilter.SHOW_TEXT);const nodes=[];while(walker.nextNode())nodes.push(walker.currentNode);nodes.forEach(n=>{if(n.parentElement.closest('script,style,select,option'))return;if(!n.datasetFr)n.datasetFr=n.nodeValue;const fr=n.datasetFr.trim();if(en&&english[fr])n.nodeValue=n.nodeValue.replace(fr,english[fr]);else if(!en)n.nodeValue=n.datasetFr})}function setLanguage(v){const en=v==='en';document.documentElement.lang=en?'en-US':'fr-FR';walkTranslate(en);if(document.querySelector('.brand'))document.querySelector('.brand').innerHTML=en?'Dico<span>horse</span>':'Dico<span>cheval</span>';document.getElementById('languageHero').value=v;localStorage.setItem('dicochevalLanguage',v)}const language=document.getElementById('languageHero');const saved=localStorage.getItem('dicochevalLanguage')||'fr';language.value=saved;language.onchange=()=>setLanguage(language.value);if(saved==='en')setLanguage('en');

