window.openBreed=function(n){let b=breeds.find(x=>x[0]===n),pony=b[1]==='Poney',en=isEnglish();let data=pony?['110–148 cm','220–400 kg',en?'varied coat colors':'robes variées',en?'hardy, intelligent':'rustique, intelligent',en?'club, trail riding, versatile':'club, randonnée, polyvalent']:['150–175 cm','450–650 kg',en?'varied coat colors':'robes variées',en?'athletic, willing':'sportif, généreux',en?'leisure and suitable disciplines':'loisir, disciplines adaptées'];if(n==='Haflinger')data=['138–155 cm','400–550 kg',en?'chestnut with flaxen mane':'alezan crins lavés',en?'family-friendly, sturdy':'familial, solide',en?'driving, versatile':'attelage, polyvalent'];if(n==='Frison')data=['155–170 cm','600–750 kg',en?'black':'noir',en?'charismatic, generous':'charismatique, généreux',en?'dressage, driving':'dressage, attelage'];document.getElementById('mtype').textContent=(en?'BREED PROFILE · ':'FICHE RACE · ')+(en?(pony?'Pony':'Horse'):b[1]);document.getElementById('mtitle').textContent=n;document.getElementById('mdesc').textContent=en?`${n} is an equine breed to discover. Its characteristics may vary from one individual to another.`:`Le ${n} est une race équine à découvrir. Les caractéristiques peuvent varier selon chaque individu.`;let labels=en?['Height','Weight','Coat colors','Qualities','Disciplines','Note']:['Taille','Poids','Robes','Qualités','Disciplines','À savoir'];let note=en?'Respectful education is essential.':'Une éducation respectueuse est essentielle.';document.getElementById('profile').innerHTML=[[labels[0],data[0]],[labels[1],data[1]],[labels[2],data[2]],[labels[3],data[3]],[labels[4],data[4]],[labels[5],note]].map(x=>`<div><b>${x[0]}</b><br>${x[1]}</div>`).join('');document.getElementById('google').href='https://www.google.com/search?tbm=isch&q='+encodeURIComponent(n+' horse breed');document.getElementById('google').textContent=en?'Search on Google ↗':'Rechercher sur Google ↗';document.getElementById('modal').classList.add('open')};
